beginning.embedded_functions:
//each function name should be prefixed by em_
/**
* Return:
* - 0: ok
* - 1: invalid
* - 2: NULL
*/
static inline int em_check_gnb_unstable_sctp(const struct ngap_session *ngap_session) {
    // gNB unstable SCTP association behavior
    const uint8_t *sctp_assoc = ngap_session->sctp_assoc;
    if (sctp_assoc == NULL || sctp_assoc[0] != 0x00) return 1; // invalid association
    uint16_t assoc_len = sctp_assoc[1];
    for (uint16_t i = 2; i <= assoc_len; ++i) {
        if ((sctp_assoc[i] & 0x80) == 0) break;
    }
    if (assoc_len < 5 || sctp_assoc[4 + assoc_len - 5] != 0x00) return 1; // incomplete association
    return 0;
}
